class Solution:
    def countPrefixSuffixPairs(self, words):
        count = 0
        for i in range(len(words)):
            for j in range(i + 1, len(words)):
                s1, s2 = words[i], words[j]
                if len(s1) <= len(s2) and s2.startswith(s1) and s2.endswith(s1):
                    count += 1
        return count

