class Solution:
    def countPrefixSuffixPairs(self, words):
        trie = {}
        count = 0
        for word in words:
            L = len(word)
            # Walk signature, accumulate counts at each node (words whose full signature ends there)
            cur = trie
            for i in range(L):
                key = (word[i], word[L - 1 - i])
                if key not in cur:
                    cur[key] = {'#': 0}
                cur = cur[key]
                count += cur['#']
            # Insert: increment terminal count
            cur2 = trie
            for i in range(L):
                key = (word[i], word[L - 1 - i])
                cur2 = cur2[key]
            cur2['#'] += 1
        return count

