var countPrefixSuffixPairs = function(words) {
    const trie = {};
    let count = 0;
    for (const word of words) {
        const L = word.length;
        // Walk and accumulate
        let cur = trie;
        for (let i = 0; i < L; i++) {
            const key = word[i] + '|' + word[L - 1 - i];
            if (!cur[key]) cur[key] = { '#': 0 };
            cur = cur[key];
            count += cur['#'];
        }
        // Insert
        let cur2 = trie;
        for (let i = 0; i < L; i++) {
            const key = word[i] + '|' + word[L - 1 - i];
            cur2 = cur2[key];
        }
        cur2['#']++;
    }
    return count;
};
